// Create builds a monitor and inserts it into the database
// Relations objects are also inserted and placed in the .R field
func (o *MonitorTemplate) Create(ctx context.Context, exec bob.Executor) (*models.Monitor, error) {
	var err error
	opt := o.BuildSetter()
	ensureCreatableMonitor(opt)

	if o.r.User == nil {
		MonitorMods.WithNewUser().Apply(ctx, o)
	}

	var rel1 *models.User

	if o.r.User.o.alreadyPersisted {
		rel1 = o.r.User.o.Build()
	} else {
		rel1, err = o.r.User.o.Create(ctx, exec)
		if err != nil {
			return nil, err
		}
	}

	opt.UserID = omit.From(rel1.ID)

	m, err := models.Monitors.Insert(opt).One(ctx, exec)
	if err != nil {
		return nil, err
	}

	m.R.User = rel1

	if err := o.insertOptRels(ctx, exec, m); err != nil {
		return nil, err
	}
	return m, err
}

